inbound.trace:
@{
                return JsonConvert.SerializeObject(new {
                    EventName = "AIGatewayRequest",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    SubscriptionName = context.Subscription?.Name ?? "anonymous",
                    Operation = context.Operation.Name,
                    ApiId = context.Api.Id,
                    ApiName = context.Api.Name,
                    Method = context.Request.Method,
                    Url = context.Request.Url.ToString(),
                    ClientIP = context.Request.IpAddress,
                    Timestamp = DateTime.UtcNow
                });
            }

outbound.trace:
@{
                var statusCode = context.Response.StatusCode;
                return JsonConvert.SerializeObject(new {
                    EventName = "AIGatewayResponse",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    Operation = context.Operation.Name,
                    ResponseCode = statusCode,
                    Duration = context.Variables["requestDuration"],
                    ResponseSize = context.Response.Body?.As<string>()?.Length ?? 0,
                    Timestamp = DateTime.UtcNow,
                    Success = (statusCode >= 200 && statusCode < 300)
                });
            }

on-error.trace:
@{
                var error = context.LastError;
                return JsonConvert.SerializeObject(new {
                    EventName = "AIGatewayError",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    Operation = context.Operation.Name,
                    ErrorSource = error?.Source,
                    ErrorReason = error?.Reason,
                    ErrorMessage = error?.Message,
                    ResponseCode = context.Response?.StatusCode ?? 500,
                    Timestamp = DateTime.UtcNow
                });
            }
